// ── Persistência ─────────────────────────────────────────
let DB = loadDB();

function loadDB() {
  try {
    const raw = localStorage.getItem(STORE_KEY);
    if (!raw) return defaultData();
    const d   = JSON.parse(raw);
    const def = defaultData();

    // Garante campos obrigatórios
    if (!d.config)    d.config    = def.config;
    if (!d.users)     d.users     = def.users;
    if (!d.jogadores) d.jogadores = [];
    if (!d.jogos)     d.jogos     = [];
    if (!d.gols)      d.gols      = [];

    // Sincroniza escudos automaticamente a partir do codigo-fonte.
    // Assim, atualizar data.js reflete sem apagar jogos/resultados salvos.
    const escudosDefault = {};
    def.equipes.forEach(e => { escudosDefault[e.id] = e.escudo; });

    if (d.equipes) {
      d.equipes.forEach(e => {
        if (escudosDefault[e.id] !== undefined) {
          e.escudo = escudosDefault[e.id];
        }
      });
    } else {
      d.equipes = def.equipes;
    }

    return d;
  } catch (e) {
    return defaultData();
  }
}

function saveDB() {
  localStorage.setItem(STORE_KEY, JSON.stringify(DB));
}

// ── Query helpers ─────────────────────────────────────────
function uid() {
  return '_' + Math.random().toString(36).substr(2, 9);
}

function getTeams(cat)            { return DB.equipes.filter(e => e.cat === cat); }
function getTeam(id)              { return DB.equipes.find(e => e.id === id); }
function getMatches(cat)          { return DB.jogos.filter(j => j.cat === cat); }
function getMatch(id)             { return DB.jogos.find(j => j.id === id); }
function getPlayers(cat, timeid)  { return DB.jogadores.filter(j => j.cat === cat && (!timeid || j.timeid === timeid)); }
function getGoals(cat, jogoid)    { return DB.gols.filter(g => g.cat === cat && (!jogoid || g.jogoid === jogoid)); }

// ── Classificação (standings) ─────────────────────────────
function computeStandings(cat, grupo) {
  const teams   = DB.equipes.filter(e => e.cat === cat && (!grupo || e.grupo === grupo));
  const matches = DB.jogos.filter(j => j.cat === cat && j.played && ['A','B','C','D'].includes(j.fase));

  const stats = {};
  teams.forEach(t => {
    stats[t.id] = { id: t.id, j: 0, v: 0, e: 0, d: 0, gp: 0, gc: 0, pts: 0 };
  });

  matches.forEach(m => {
    const g1 = parseInt(m.g1 || 0);
    const g2 = parseInt(m.g2 || 0);

    function upd(a, ga, gb) {
      if (!stats[a]) return;
      stats[a].j++;  stats[a].gp += ga;  stats[a].gc += gb;
      if      (ga > gb) { stats[a].v++; stats[a].pts += 3; }
      else if (ga === gb) { stats[a].e++; stats[a].pts += 1; }
      else                { stats[a].d++; }
    }
    upd(m.t1, g1, g2);
    upd(m.t2, g2, g1);
  });

  return teams
    .map(t => ({ ...t, ...stats[t.id] }))
    .sort((a, b) => {
      if (b.pts !== a.pts) return b.pts - a.pts;
      const sdA = a.gp - a.gc, sdB = b.gp - b.gc;
      if (sdB !== sdA) return sdB - sdA;
      return b.gp - a.gp;
    });
}

// ── Artilharia ────────────────────────────────────────────
function computeScorers(cat) {
  const goals = DB.gols.filter(g => g.cat === cat);
  const map   = {};

  goals.forEach(g => {
    const key = g.jogadorid || g.jogador;
    if (!map[key]) {
      const t = getTeam(g.timeid);
      map[key] = { nome: g.jogador, time: t ? t.nome : '?', flag: t ? t.flag : '?', gols: 0 };
    }
    map[key].gols++;
  });

  return Object.values(map).sort((a, b) => b.gols - a.gols);
}

// ── Bracket helpers ───────────────────────────────────────
function getBracketLeader(cat, grupo) {
  const rows = computeStandings(cat, grupo);
  return rows.length > 0 ? rows[0] : null;
}

function getBracketMatch(cat, fase, sfNum) {
  if (sfNum !== undefined) {
    return DB.jogos.find(j => j.cat === cat && j.fase === fase && j.sf_num === sfNum)
        || DB.jogos.filter(j => j.cat === cat && j.fase === fase)[sfNum - 1];
  }
  return DB.jogos.find(j => j.cat === cat && j.fase === fase);
}

function getMatchWinner(m) {
  if (!m || !m.played) return null;
  if (parseInt(m.g1) > parseInt(m.g2)) return getTeam(m.t1);
  if (parseInt(m.g2) > parseInt(m.g1)) return getTeam(m.t2);
  return null;
}

function getMatchLoser(m) {
  if (!m || !m.played) return null;
  if (parseInt(m.g1) < parseInt(m.g2)) return getTeam(m.t1);
  if (parseInt(m.g2) < parseInt(m.g1)) return getTeam(m.t2);
  return null;
}